import{j as e}from"./ui-vendor-CUvJdy9K.js";import{L as a}from"./LocalLandingPage-D3kQhD6_.js";import{P as r}from"./index-C03muQI3.js";import{U as n}from"./utensils-crossed-DsHIjML5.js";import"./react-vendor-CSY-tL5Y.js";import"./Footer-BLN0AZOI.js";import"./phone-CNIer0s9.js";import"./AnimatedSection-C8ujN5LE.js";import"./Contact-CG2Q6yAh.js";import"./use-toast-Nf-M9DeG.js";import"./input-CclBXkxa.js";import"./utils-BLSKlp9E.js";import"./map-pin-B7--qKK4.js";import"./circle-check-big-DPMznW8r.js";import"./sections-CSJ2HaIa.js";import"./accordion-C-rbFL94.js";const t={city:"Västmanland",slug:"hemsidor-restaurang",serviceKeyword:"Hemsida restaurang",metaTitle:"Hemsida Restaurang Västmanland – Fyll fler bord | LRH Konsult",metaDescription:"Vi bygger snabba, bokningsvänliga hemsidor för restauranger i Västmanland. Få fler bord med lokal SEO, mobil meny och online-bokning.",heroHeading:"Hemsida restaurang som fyller borden i Västmanland",heroDescription:"Hungriga gäster söker efter lunch och middag online. Vi bygger restauranghemsidor som syns i Google, visar din meny och tar emot bokningar – utan att tappa prestanda.",icon:n,heroFacts:["100/100 PageSpeed – snabbaste restaurangsidorna i Västmanland","Responsiva menyer som rankar i Google – inga PDF:er","Online-bokning utan provision till tredjepartstjänster","JSON-LD Restaurant-schema för bättre synlighet i sökresultaten"],benefits:[{title:"Mobilanpassad meny",description:"Responsiva menyer som läses direkt i mobilen utan att behöva scrolla eller zooma – eftersom de är byggda i HTML och indexeras av Google."},{title:"Bokningssystem som konverterar",description:"Onlinebokning direkt i hemsidan utan dyra provisioner. Vi optimerar flödet för att få konverteringar från första klicket."},{title:"Lokal SEO för restauranger",description:"Vi optimerar din webbplats för söktermer som 'restaurang Västmanland', 'lunch Västerås' och 'boka bord Köping' med schema, metadata och lokal landningssida."},{title:"Prestanda som påverkar ranking",description:"Med 100/100 PageSpeed får du snabbare upplevelse, bättre ranking och mindre avhopp – viktigt för restauranger som lever på spontanbesök."}],bodyTitle:"Moderna restauranghemsidor för Västmanland",bodyParagraphs:["En restauranghemsida måste göra tre saker, och den måste göra dem snabbt: visa meny, visa öppettider och göra bokningen enkel. I Västmanland söker gäster på Google innan de tar sig till bordet, och varje millisekund i laddningstid kan avgöra om de väljer din restaurang eller konkurrenten. Vi bygger restauranghemsidor som klarar den pressen och levererar en sömlös upplevelse – från första Google-klick till bokad middag.","Många restauranger använder fortfarande PDF-menyer som kräver zoom och som aldrig indexeras av Google. Det gör det svårt för nya kunder att hitta din meny när de söker efter 'pizza Västmanland' eller 'vegan lunch Köping'. Vi bygger istället responsiva HTML-menyer som är sökbara, tillgängliga och optimerade för mobil, så att din mat syns i sökresultaten.","Online-bokning är en av de viktigaste konverteringspunkterna för restauranger. Vi skapar bokningsflöden som är designade för att minska friktion: inga formulär som känns långa, inga redirect till tredje partsplattformar, och inga provisioner per bokning. Bokningen kan integreras med din kalender eller hanteras via ett lätt administrerat gränssnitt.","För att restauranger i Västmanland ska synas behöver hemsidan vara tekniskt optimerad. Google prioriterar snabb laddning och bra mobilupplevelse i sina rankingalgoritmer. Vi når 100/100 i PageSpeed Insights genom att optimera bilder till AVIF, använda server-side rendering och minimera onödig JavaScript. Det ger bättre ranking och fler gäster som hittar dig via sök.","Lokalt fokus är viktigt. Vi hjälper restauranger att ranka på sökningar som 'restaurang Västerås', 'lunch Sala' och 'boka bord Köping'. Genom att skapa landningssidor som talar direkt till lokala matgäster och par med rätt schema-markup, ökar vi chanserna att du syns i kartpaketet och som ett rikt utdrag i sökresultaten.","För att komma igång med en ny hemsida rekommenderar vi en gratis SEO-analys. Det ger dig en tydlig bild över hur din nuvarande online-närvaro presterar och var vi kan göra störst skillnad. Besök vår sida för [gratis SEO-analys](/gratis-seo-analys) eller se hur vi bygger skräddarsydda lösningar på [webbutveckling](/tjanster/webbutveckling) och [SEO-optimering](/tjanster/seo-optimering)."],bodyExtraSections:[{title:"Online bokning utan provision – från klick till bord",paragraphs:["Bokningsplattformar tar ofta 10–20% i provision per bokning. För en restaurang som gör 20 bokningar per vecka kan det bli en betydande kostnad. Vi bygger bokningssystem direkt i din hemsida som inte tar någon provision – det är en investering som snabbt betalar sig.","Bokningsflödet designas för att minimera avhopp. Vi använder tydliga call-to-actions, smarta formulärvalideringar och en mobilvänlig design som gör det enkelt att boka med ett fåtal tryck. Du kan även styra hur mycket information du vill samla in – från endast namn och telefonnummer till fler val som särskilda önskemål eller allergier.","För restauranger som vill synka bokningar med sitt POS-system eller kalendrar finns det möjlighet att koppla via API:er eller enklare export/importflöden. Målet är att ge dig full kontroll utan onödig komplexitet."]},{title:"Responsiva menyer som rankar i Google",paragraphs:["Menyer är det viktigaste innehållet på en restaurangs hemsida, men de indexeras sällan om de ligger inbäddade som PDF. Genom att bygga menyer med semantisk HTML och Schema.org Menu-schema kan vi få dina rätter att dyka upp i sökresultaten på sökningar som 'vegan pizza Västmanland' eller 'lunch buffé Köping'.","Vi designar menyer som är lätta att skanna på mobilen, med tydliga sektioner, priser och allergeninformation. Menyn kan uppdateras enkelt via ett CMS eller ett admin-gränssnitt så att du kan hålla den aktuell utan att behöva kontakta utvecklaren varje gång.","Vi optimerar även för bilder i menyn – från förrätt till dessert. Rätterna laddar snabbt med AVIF och lazy-loading, samtidigt som de ser aptitliga ut på alla enheter. Det gör att dina gäster har en positiv upplevelse redan innan de bokar bord."]},{title:"Lokal SEO för restaurang i Västmanland",paragraphs:["Lokal SEO handlar om mer än bara sökord – det handlar om att bygga förtroende hos gäster i ditt område. Vi optimerar din Google Business-profil, lägger till rätt kategori, öppettider, meny och bilder, och arbetar kontinuerligt med att samla äkta kundrecensioner.","På hemsidan implementerar vi JSON-LD Restaurant-schema, LocalBusiness-schema och FAQ-schema för att öka sannolikheten att din restaurang visas med rika utdrag i sökresultaten. Det gör att din sida sticker ut och får fler klick – särskilt för sökningar som 'boka bord Sala' eller 'restaurang Västmanland'.","Genom att skapa lokalt inriktat innehåll – till exempel 'Veckans lunch i Västerås' eller 'Säsongens meny i Köping' – kan vi fånga upp säsongsspecifika sökningar och hålla din sajt relevant året runt. Det ger en stabil trafikökning och fler bokningar."]},{title:"Restauranger i Västmanland som vinner online",paragraphs:["Många restauranger i Västmanland förlitar sig på sociala medier eller externa bokningsplattformar. Det ger dem begränsad kontroll över sina kundrelationer och gör dem sårbara för förändringar i plattformarnas villkor. En egen hemsida ger dig full kontroll över ditt innehåll, din data och din kundupplevelse.","Vi har jobbat med restauranger av alla storlekar – från små lunchställen i Köping till fullservicerestauranger i Västerås. Oavsett om du vill öka lunchförsäljningen, fylla borden på vardagskvällar eller öka antalet återkommande gäster, hjälper vi dig att skapa en hemsida som levererar resultat.","Det handlar inte bara om att synas – det handlar om att tydligt kommunicera vad som gör din restaurang unik. Vi hjälper dig att lyfta fram din meny, din atmosfär och din service så att gästerna vet varför de ska välja just dig."]}],caseStudy:{title:"Projektinsikt: Lunchrestaurang i Västmanland fyllde bord med ny hemsida",problem:"En lunchrestaurang i Västerås hade inte en fungerande hemsida och förlitade sig på Facebook och Google Maps. De visade aldrig sin aktuella meny och hade ingen bokningslösning, vilket gjorde att besökare snabbt valde andra restauranger när deras egen information var föråldrad.",solution:"Vi byggde en mobilfokuserad restauranghemsida med dynamisk meny, onlinebokning och Google Business-integrering. Enkla redigeringsverktyg gjorde det möjligt för personalen att uppdatera dagens lunch varje morgon. Vi implementerade Restaurant-schema och optimerade sidan för sökningar som 'lunch Västerås' och 'boka bord Sala'.",result:"Inom fyra veckor rankade sidan topp 3 för 'lunch Västerås' och 'bokning restaurang Sala'. Restaurangen såg en 180% ökning i direktbokningar via hemsidan och kunde minska antalet samtal med 40%, vilket frigjorde personalresurser under rusningstid."},faq:[{question:"Behöver en restaurang verkligen en egen hemsida?",answer:"Ja. En egen hemsida ger dig full kontroll över din meny, dina öppettider och din bokning. Den gör också att du syns i Google istället för att vara beroende av tredjepartsplattformar."},{question:"Kan ni bygga bokningssystem utan provision?",answer:"Ja. Vi bygger bokningslösningar direkt i din hemsida utan att ta provision per bokning. Det sparar pengar och ger dig bättre kunddata."},{question:"Hur snabbt kan jag uppdatera menyn?",answer:"Vi implementerar enkla redigeringsverktyg så att du kan uppdatera menyn själv på några minuter. Vill du hellre skicka ändringar till oss hjälper vi gärna till."},{question:"Kan ni hjälpa mig med Google Business och recensioner?",answer:"Absolut. Vi optimerar din Google Business-profil och hjälper till att skapa en strategi för att samla in äkta recensioner från nöjda gäster."},{question:"Vad kostar en restauranghemsida?",answer:"Priserna startar vid 5 000 kr. För en detaljerad offert, börja med en [gratis SEO-analys](/gratis-seo-analys) och se hur vi kan hjälpa din restaurang att växa."}]},V=()=>e.jsxs(e.Fragment,{children:[e.jsx(r,{title:"Hemsida för restaurang Västmanland | LRH Konsult",description:"Professionell restauranghemsida med meny och bokningssystem. LRH Konsult hjälper restauranger i Västmanland."}),e.jsx(a,{config:t})]});export{V as default};
